import React from "react";

function LoginPage() {
  return (
    <div style={styles.container}>
      
      {/* LEFT CARD */}
      <div style={styles.card}>
        
        {/* Tabs */}
        <div style={styles.tabs}>
          <span style={{ ...styles.tab, ...styles.activeTab }}>Login</span>
          <span style={styles.tab}>Register</span>
        </div>

        {/* Form */}
        <div style={styles.form}>
          <label>Email</label>
          <input type="email" style={styles.input} />

          <label>Password</label>
          <input type="password" style={styles.input} />

          <div style={styles.remember}>
            <input type="checkbox" />
            <span>Remember Me</span>
          </div>

          <button style={styles.button}>Login</button>

          <p style={styles.text}>
            Don’t have an account? <span style={styles.link}>Register</span>
          </p>
        </div>
      </div>

      {/* RIGHT SIDE */}
      <div style={styles.side}>
        <img
          src="https://cdn-icons-png.flaticon.com/512/3064/3064197.png"
          alt="secure"
          style={styles.image}
        />
        <h2>Secure Digital Will Access</h2>
        <p style={{ color: "gray" }}>Your data is securely stored</p>
      </div>
    </div>
  );
}

export default LoginPage;


/* ================= STYLES ================= */

const styles = {
  container: {
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    height: "100vh",
    gap: "50px",
    background: "linear-gradient(to right, #eef2f7, #f9fbfd)",
    fontFamily: "Arial"
  },

  card: {
    width: "350px",
    background: "#fff",
    borderRadius: "10px",
    padding: "20px",
    boxShadow: "0 5px 15px rgba(0,0,0,0.1)"
  },

  tabs: {
    display: "flex",
    justifyContent: "space-around",
    marginBottom: "20px"
  },

  tab: {
    cursor: "pointer"
  },

  activeTab: {
    borderBottom: "2px solid blue",
    color: "blue"
  },

  form: {
    display: "flex",
    flexDirection: "column"
  },

  input: {
    padding: "10px",
    margin: "5px 0 10px 0",
    borderRadius: "5px",
    border: "1px solid #ccc"
  },

  remember: {
    display: "flex",
    alignItems: "center",
    gap: "5px"
  },

  button: {
    marginTop: "15px",
    padding: "10px",
    background: "blue",
    color: "white",
    border: "none",
    borderRadius: "5px",
    cursor: "pointer"
  },

  text: {
    marginTop: "10px",
    fontSize: "14px"
  },

  link: {
    color: "blue",
    cursor: "pointer"
  },

  side: {
    textAlign: "center"
  },

  image: {
    width: "100px"
  }
};
